patch:
--- a/synchronizer.v
+++ b/synchronizer.v
@@ -9,7 +9,7 @@
   output logic [63:0] q_out
 );

-  always @(posedge clk) begin
+  always @(posedge clk or negedge rst_n) begin
     if (~rst_n)
       q_out <= 64'b0;
     else

before_code:
module synchronizer_64bit (
  input logic clk,
  input logic rst_n,
  input logic [63:0] d_in,
  output logic [63:0] q_out
);

  always @(posedge clk) begin
    if (~rst_n)
      q_out <= 64'b0;
    else
      q_out <= d_in;
  end

endmodule

after_code:
module synchronizer_64bit (
  input logic clk,
  input logic rst_n,
  input logic [63:0] d_in,
  output logic [63:0] q_out
);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n)
      q_out <= 64'b0;
    else
      q_out <= d_in;
  end

endmodule
